// Build the ICS content with all VTODO properties
const body = $('Webhook - Create Task').first().json.body;
const taskId = Date.now();

// Format current date for DTSTAMP (iCal format: YYYYMMDDTHHMMSSZ)
const now = new Date();
const formatICalDate = (d) => {
  const year = d.getUTCFullYear();
  const month = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  const hours = String(d.getUTCHours()).padStart(2, '0');
  const minutes = String(d.getUTCMinutes()).padStart(2, '0');
  const seconds = String(d.getUTCSeconds()).padStart(2, '0');
  return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
};

// Parse date string to Date object
const parseDate = (dateStr) => {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return isNaN(d.getTime()) ? null : d;
};

const dtstamp = formatICalDate(now);

// Build VTODO content using array and join with CRLF
const lines = [];
lines.push('BEGIN:VCALENDAR');
lines.push('VERSION:2.0');
lines.push('PRODID:-//n8n//Nextcloud//EN');
lines.push('BEGIN:VTODO');
lines.push(`UID:n8n-task-${taskId}`);
lines.push(`DTSTAMP:${dtstamp}`);

// SUMMARY (required)
if (body.title) {
  lines.push(`SUMMARY:${body.title}`);
}

// DESCRIPTION
if (body.description) {
  lines.push(`DESCRIPTION:${body.description}`);
}

// DUE (due date)
if (body.due) {
  const dueDate = parseDate(body.due);
  if (dueDate) lines.push(`DUE:${formatICalDate(dueDate)}`);
}

// DTSTART (start date)
if (body.startDate) {
  const startDate = parseDate(body.startDate);
  if (startDate) lines.push(`DTSTART:${formatICalDate(startDate)}`);
}

// COMPLETED (completion date)
if (body.completed) {
  const completedDate = parseDate(body.completed);
  if (completedDate) lines.push(`COMPLETED:${formatICalDate(completedDate)}`);
}

// STATUS: NEEDS-ACTION, COMPLETED, IN-PROCESS, CANCELLED
if (body.status) {
  const statusMap = {
    'todo': 'NEEDS-ACTION',
    'in-progress': 'IN-PROCESS',
    'completed': 'COMPLETED',
    'cancelled': 'CANCELLED',
    'NEEDS-ACTION': 'NEEDS-ACTION',
    'IN-PROCESS': 'IN-PROCESS',
    'COMPLETED': 'COMPLETED',
    'CANCELLED': 'CANCELLED'
  };
  lines.push(`STATUS:${statusMap[body.status] || 'NEEDS-ACTION'}`);
} else {
  lines.push('STATUS:NEEDS-ACTION');
}

// PRIORITY (1=highest, 9=lowest)
if (body.priority !== undefined && body.priority !== null) {
  const priority = Math.min(9, Math.max(1, parseInt(body.priority)));
  lines.push(`PRIORITY:${priority}`);
}

// PERCENT-COMPLETE
if (body.percentComplete !== undefined) {
  const percent = Math.min(100, Math.max(0, parseInt(body.percentComplete)));
  lines.push(`PERCENT-COMPLETE:${percent}`);
}

// CATEGORIES (comma-separated tags)
if (body.categories) {
  const cats = Array.isArray(body.categories) ? body.categories.join(',') : body.categories;
  lines.push(`CATEGORIES:${cats}`);
}

// RELATED-TO (parent task UID)
if (body.parentTaskUid) {
  lines.push(`RELATED-TO;RELTYPE=PARENT:${body.parentTaskUid}`);
}

// DURATION (e.g., PT1H for 1 hour, P1D for 1 day)
if (body.duration) {
  lines.push(`DURATION:${body.duration}`);
}

// RRULE (recurrence rule)
if (body.recurrence) {
  lines.push(`RRULE:${body.recurrence}`);
}

// URL (link to task)
if (body.url) {
  lines.push(`URL:${body.url}`);
}

// LOCATION
if (body.location) {
  lines.push(`LOCATION:${body.location}`);
}

lines.push('END:VTODO');
lines.push('END:VCALENDAR');

// Join with CRLF (required by iCal spec)
const icsBody = lines.join('\r\n');

return [{
  json: {
    nextcloudUrl: $('Set Config').first().json.nextcloudUrl,
    nextcloudUser: $('Set Config').first().json.nextcloudUser,
    icsBody
  }
}];

const response = $input.first();
const body = $('Webhook - Create Task').first().json.body;

if (response.json.statusCode === 201 || response.json.statusCode === 204 || !response.json.error) {
  return [{
    json: {
      success: true,
      message: 'Task created successfully!',
      task: {
        title: body.title,
        description: body.description || null,
        due: body.due || null,
        startDate: body.startDate || null,
        status: body.status || 'NEEDS-ACTION',
        priority: body.priority || null,
        percentComplete: body.percentComplete || 0,
        categories: body.categories || null,
        parentTaskUid: body.parentTaskUid || null,
        duration: body.duration || null,
        recurrence: body.recurrence || null
      }
    }
  }];
} else {
  return [{
    json: {
      success: false,
      message: 'Failed to create task',
      error: response.json
    }
  }];
}
